from flask import Flask, request, jsonify
from flask_sqlalchemy import SQLAlchemy

app = Flask(__name__)
app.config['SQLALCHEMY_DATABASE_URI'] = 'sqlite:////tmp/test.db'
db = SQLAlchemy(app)

class User(db.Model):
    id = db.Column(db.Integer, primary_key=True)
    username = db.Column(db.String(80), nullable=False)
    email = db.Column(db.String(120), unique=True, nullable=False)
    role = db.Column(db.String(20))
    account_status = db.Column(db.String(20))
    subscription_tier = db.Column(db.String(50))

@app.route('/api/users/<int:user_id>', methods=['PUT'])
def update_user(user_id):
    user = User.query.get_or_404(user_id)

    if current_user.is_authenticated and current_user.is_admin:
        user.email = request.json.get('email', user.email)
        user.username = request.json.get('username', user.username)
        user.role = request.json.get('role', user.role)
        user.account_status = request.json.get('account_status', user.account_status)
        user.subscription_tier = request.json.get('subscription_tier', user.subscription_tier)

        db.session.commit()
        return jsonify({'message': 'User updated successfully.'})
    else:
        return jsonify({'error': 'Unauthorized.'}), 401

